{"code": "import json
import os

# Load Europe metadata
metadata_file = var_functions.query_db:28
with open(metadata_file, 'r') as f:
    europe_metadata = json.load(f)

# Load articles data
articles_data = var_functions.query_db:30

# Create article lookup dictionary
articles_dict = {str(art['article_id']): {'title': art['title'], 'description': art['description']} for art in articles_data}

# Filter for years 2010-2020 and create year-article mapping
europe_articles_by_year = {}
for meta in europe_metadata:
    year = int(meta['publication_date'].split('-')[0])
    if 2010 <= year <= 2020:
        article_id = str(meta['article_id'])
        if article_id in articles_dict:
            if year not in europe_articles_by_year:
                europe_articles_by_year[year] = []
            europe_articles_by_year[year].append({
                'article_id': article_id,
                'title': articles_dict[article_id]['title'],
                'description': articles_dict[article_id]['description']
            })

print('__RESULT__:')
print(json.dumps({
    'total_europe_articles_2010_2020': sum(len(v) for v in europe_articles_by_year.values()),
    'years_covered': sorted(europe_articles_by_year.keys()),
    'articles_per_year': {k: len(v) for k, v in europe_articles_by_year.items()}
}))"}

